using UnityEngine; using UnityEngine.Events;  public class KnightScript1 : MonoBehaviour {  public Rock rock;     public UnityEvent OnEnter;     public UnityEvent OnLeave;      public UnityEvent<float> OnEnterWithValue;      private SpriteRenderer hazardRenderer;     private bool wasInTheHazard = false;       // Start is called once before the first execution of Update after the MonoBehaviour is created     void Start()     {         hazardRenderer = GetComponent<SpriteRenderer>();     }      // Update is called once per frame     void Update()     {         bool isInTheHazard = hazardRenderer.bounds.Contains(rock.transform.position);         if (isInTheHazard             && wasInTheHazard == false)         {             wasInTheHazard = true;             // WHAT WE WANT TO HAVE HAPPEN WHEN THE PLAYER ENTERS THE SENSOR             OnEnter.Invoke();         }         else if (!isInTheHazard && wasInTheHazard)         {             wasInTheHazard = false;             // WHAT WE WANT TO HAVE HAPPEN WHEN THE PLAYER EXITS THE SENSOR             OnLeave.Invoke();         }     } }